INSERT INTO articles (id, title, teaser, text, author_id, published_at) VALUES (1, 'Merry Christmas', 'Ja wo bist du denn hier gelandet? Einfach mal hier drauf klicken :)', 'Das ist deine neue Webseite zum Rezepte sammeln. Ich hatte eigentlich gehofft dass ich die Seite bis Weihnachten ganz fertig kriege, aber es ist wie immer ;) alles ein bisschen komplizierter als man denkt.
INSERT INTO articles (id, title, teaser, text, author_id, published_at) VALUES (2, 'Willkommen auf Foodblog.ch', '', '', 2, '2017-01-12T08:05:00.0000000+00:00');
INSERT INTO articles (id, title, teaser, text, author_id, published_at) VALUES (3, 'Die Bärlauchzeit ist da...', 'Die Tage werden länger, die Wiesen wieder bunt und auch Bärlauch ist wieder in Massen zu finden.', 'Der Frühling ist da und damit auch einige beliebte Küchenkräuter.
INSERT INTO articles (id, title, teaser, text, author_id, published_at) VALUES (4, 'Macarons selbst backen', 'Jeder hat sie zumindest schon gesehen: die hübschen bunten Macarons. Neben ihrem tollen Aussehen schmecken sie auch fantastisch. Und wer nicht für diese kleinen teuren Gebäcke zahlen möchte, der kann versuchen sie selbst zu machen.', 'Jeder kennt sie: die bunten kleinen Eiweissgebäcke von Sprüngli oder Ladurée und vielen anderen Macaronsherstellern. Sie alle haben folgendes gemeinsam: sie sind bunt, sie sind lecker und sie sind teuer.
INSERT INTO ingredients (id, name, image, description, density, piece_count, calorific_value, protein, fat, carbohydrates, sugar, fiber) VALUES (1, 'Mayonnaise', '', 'Mayonnaise ist eine dickflüssige, kalt hergestellte Sauce auf der Basis von Eigelb und Öl', 1, 1, 0, 0, 0, 0, 0, 0);
