INSERT INTO ingredients (id, name, image, description, density, piece_count, calorific_value, protein, fat, carbohydrates, sugar, fiber) VALUES (37, 'Spaghetti', '', 'Sind eine Form von Teigwaren und Nudeln aus Hartweizen mit rundem Querschnitt, etwa zwei Millimeter Durchmesser und etwa 25 cm Länge. Sie stammen aus Italien.', 1, 1, 1, 0, 0, 0, 0, 0);
