INSERT INTO ingredients (id, name, image, description, density, piece_count, calorific_value, protein, fat, carbohydrates, sugar, fiber) VALUES (39, 'Creme Fraiche', '', 'Crème fraîche ist ein ursprünglich in Frankreich entwickeltes Sauerrahmerzeugnis. Es wird aus Kuhmilch hergestellt und muss einen Mindestfettgehalt von 30 Prozent haben.', 1, 1, 1, 0, 0, 0, 0, 0);
INSERT INTO ingredients (id, name, image, description, density, piece_count, calorific_value, protein, fat, carbohydrates, sugar, fiber) VALUES (40, 'Basilikum', '', 'Das Basilikum, auch Basilie, Basilienkraut oder Königskraut genannt, ist eine Gewürzpflanze aus der gleichnamigen Gattung Basilikum der Familie der Lippenblütler', 0, 1, 172, 3, 1, 5, 0, 3);
