INSERT INTO ingredients (id, name, image, description, density, piece_count, calorific_value, protein, fat, carbohydrates, sugar, fiber) VALUES (44, 'Butter', '', 'Butter ist ein meist aus dem Rahm von Milch hergestelltes Streichfett, das nach EU-Verordnung zu mindestens 80 Prozent aus Milchfett besteht. Überwiegend wird Butter aus Kuhmilch hergestellt, doch es gibt auch Butter aus Schafmilch und Ziegenmilch.', 1, 1, 3102, 1, 83, 1, 1, 0);
