INSERT INTO recipes (id, name, description, author_id, difficulty, portions) VALUES (11, 'Kaiserschmarrn', 'Kaiserschmarrn, eine verfeinerte Form des Schmarrns, ist eine Zubereitung aus Palatschinkenteig und zählt zu den bekanntesten Süßspeisen der österreichischen Küche.', 1, 2, 2);
INSERT INTO recipes (id, name, description, author_id, difficulty, portions) VALUES (12, 'Vanillegipferl', 'Vanillegipferl oder Vanillekipferl sind ein Österreichisches Gebäck welches oft in der Vorweihnachtszeit gebacken wird und aus einem Mürbteig aus Mehl, Butter, Zucker und gemahlenen Mandeln besteht. Das Gebäck ist so zart, dass es auf der Zunge zergeht.', 1, 2, 60);
