INSERT INTO recipes (id, name, description, author_id, difficulty, portions) VALUES (28, 'American Pancakes', 'Die Amerikanische Form der Pfannkuchen ist im Gegensatz zum Pfannkuchen wie er in unseren Graden gemacht wird vor allem dicker und luftiger. Dies ist eine Folge des Teelöffels Backpulver. Der Anblick eines wunderschönen Pancakes-Turm macht schon mal richtig Lust und zusammen mit Ahorn-Sirup einfach grossartig.', 1, 0, 2);
