INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (1, 0, 'Semmel in Milch einweichen und danach ausdrücken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (1, 1, 'Zwiebel fein hacken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (1, 2, 'Hackfleisch, Zwiebel, Knoblauch, eingeweichte Semmel, Ei, Mehl, Paniermehl und die Gewürze in eine gemeinsame Schüssel geben und zu einem Teig kneten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (1, 3, 'Den Fleischteig in gleichgrosse Portionen teilen, in Hamburger formen und in Paniermehl wenden. Das Fleisch nun mit wenig Öl in der heissen Pfanne anbraten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (1, 4, 'Nach belieben weiterverarbeiten...');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (2, 0, 'Alle Zutaten in einer Schüssel zusammenrühren');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (2, 1, 'Sauce bis zum gebrauch kalt stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 0, 'Vermische das Wasser mit der Erdbeermarmelade in einer Schüssel und schneide den Apfel in sehr feine Streifen. Lege die Apfelstreifen in eine Schale mit Wasser und etwas Zitronensaft.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 1, 'Rolle den Blätterteig aus und schneide ihn in vier gleichgrosse Streifen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 2, 'Bestreiche nun alle vier Streifen auf der oberen Hälfte mit dem Erdbeermarmelade-Wasser-Gemisch und streue etwas Zucker darüber.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 3, 'Nun werden die Apfelstreifen Stück für Stück überlappend auf die Marmelade gelegt. Die Apfelspitzen sollten oben über den Blätterteig hinausragen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 4, 'Streue noch einmal etwas Zucker über die Äpfel und klappe den unteren Teil über die Äpfel, sodass diese in dem Blätterteig stecken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 5, 'Rolle den Blätterteig nun auf und stell ihn in eine Muffinform. Bei Bedarf kann man nun noch etwas Zimt darüber streuen. Anschliessend kommt alles für 45 Minuten in den Backofen bei 180°C.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (3, 6, 'Nach dem Backen noch mit Puderzucker bestreuen und servieren, warm oder kalt.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 0, 'Den Blätterteig aus dem Kühlschrank nehmen und ausrollen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 1, 'Bestreiche den Blätterteig nun mit dem Frischkäse und streue Dill darüber.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 2, 'Lege nun den Räucherlachs darüber und rolle den Blätterteig wieder auf.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 3, 'Dieser Schritt kann weggelassen werden, erleichtert das Schneiden aber: Lege den Blätterteig für ca. 20 Minuten in den Tiefkühler.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 4, 'Schneide die Rolle nun in ca. 1cm breite Rollen und lege sie auf ein mit Backpapier ausgelegtes Backblech.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (4, 5, 'Backe die Schnecken für ca. 20 Minuten bei 200°C.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (5, 0, 'Spaghetti nach Packungsanweisung kochen. Das Rezept funktioniert mit frischen oder tiefgekühlten Erdbeeren. - Die tiefgekühlten Erdbeeren sollten vor der Zubereitung leicht angetaut werden. - Frische Erdbeeren waschen und entkelchen. Erdbeeren halbieren oder vierteln.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (5, 1, 'Knoblauch schälen und fein hacken. Die Hälfte der Basilikumblätter grob zerpflücken und die andere Hälfte ganz lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (5, 2, 'Das Lachsfilet trocken tupfen und in Würfel von ca. 2cm schneiden. Das Creme Fraiche in einer Pfanne erhitzen, den Knoblauch und die Lachswürfel darin anbraten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (5, 3, 'Den Dill und das Basilikum nach Geschmack hinzufügen und mit Salz und Pfeffer abschmecken. Anschliessend die restlichen Basilikumblätter hinzufügen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (5, 4, 'Spaghetti unter die Sauce heben und servieren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (6, 0, 'Die Kartoffeln schälen und in dünne Scheiben schneiden.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (6, 1, 'Milch, Rahm und den fein gehackten Knoblauch vermischen und mit den Kartoffelscheiben in einen Topf geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (6, 2, 'Salz, Pfeffer und Rosmarin nach Bedarf hinzufügen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (6, 3, 'Alles zusammen aufkochen und unter Rühren ca. 15-20 Minuten kochen lassen bis die Kartoffelscheiben weich sind.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (6, 4, 'Alles in eine Auflaufform geben, mit Käse (und Paniermehl) bestreuen und für ca. 20 Minuten bei 220°C backen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (7, 0, 'Creme Fraiche in einer Pfanne erhitzen und das Mehl unterrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (7, 1, 'Bouillon unter Rühren hinzufügen und einige Minuten köcheln lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (7, 2, 'Schnittlauch und Petersilie hinzufügen und mit Salz und Pfeffer abschmecken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (8, 0, 'Alle Zutaten in einem Topf miteinander vermischen und aufkochen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 0, 'Alle Zutaten von Butter bis und mit gemahlene Mandeln miteinander vermischen und zu einem Teig verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 1, 'Teig in eine Auflaufform geben, die Rhabarberstückchen darauf geben und reichlich Zucker darüber streuen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 2, 'Teig mit Rhabarber ca. 25 Minuten bei 180°C Heissluft backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 3, 'In der Zwischenzeit für den Guss die Eiweiss steif schlagen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 4, 'Eigelb mit dem Zucker und Zimt vermischen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 5, 'Anschliessend die Zuckermasse und das Creme Fraiche vorsichtig unter das Eiweiss heben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (9, 6, 'Alles auf den schon vorgebackenen Boden geben und noch einmal für ca. 30 - 35 Minuten bei 180°C Heissluft backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (10, 0, 'Butter und Schokolade unter Rühren in einer Pfanne schmelzen lassen und etwas abkühlen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (10, 1, 'Alle Zutaten bis und mit Salz in eine Schüssel geben und verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (10, 2, 'Schokoladen-Butter-Masse unterrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (10, 3, 'Nüsse und Mehl daruntermischen. Teig in eine Form füllen und ca. 25 Minuten bei 180° C im vorgeheizten Ofen backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (11, 0, 'Für den Kaiserschmarrn zuerst in einer Schüssel Mehl, Zucker, Salz und Eigelb mit der Milch zu einem glatten, dickflüssigen Teig verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (11, 1, 'In einer anderen Schüssel das Eiweiss steif schlagen. Nun ist es wichtig das Eiweiss nur unterzuheben und möglichst viel Volumen zu behalten. dafür nutzt man am besten einen Teigschaber.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (11, 2, 'Die Butter in der Pfanne schmelen und dann denn Teig hineingiessen und 2-3min in der Pfanne bei mittlerer bis grosser Hitze Farbe annehmen lassen und dann im auf 180Grad vorgeheizten Ofen 5-6min zu Ende Backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (11, 3, 'Nun kann der Schmarrn zerrissen werden und in der Pfanne zuende braten bis er Goldgelb ist und dann mit Puderzucker bestreuen und am besten noch warm essen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 0, 'Mehl und Salz in eine Schüssel geben und kleine Stücke der Butter (oder Margerine) zugeben und mit kalten Händen schnell zu einer gleichmässigen Masse reiben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 1, 'Puderzucker, Zucker und Mandeln beigeben und zu einem Teig kneten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 2, 'Den Teig etwa 30min zugedeckt Kühl stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 3, 'Teig Portionsweise zwischen zwei Handflächen in etwa Stiftdicke Röllchen formen welche sich auf beiden Enden verdünnen und dann als Gipferl geformt aufs Backblech legen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 4, '10-15min in der Mitte des auf 200Grad vorgeheizten Ofens backen, nicht zu dunkel werden lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (12, 5, 'Noch warm in einem Gemisch aus Puderzucker und Vanillezucker wenden oder bestreuen und abkühlen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 0, 'Zwiebeln, Paprika, Sellerie und Knoblauch klein würfeln und zur Seite stellen. Okras in 1/2 cm dicke Schreiben schneiden.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 1, 'Andouille in dünne Scheiben schneiden (ca. 1/2 cm dick) und in einer Pfanne mit etwas Öl 5 Minuten anbraten, anschliessend aus der Pfanne nehmen und zur Seite stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 2, 'Paprika, Pfeffer und Cayennepfeffer mischen. Das geschnitte Hähnchenfleisch damit würzen, ca. 10 Minuten anbraten. Fleisch aus der Pfanne nehmen, das Öl aber drin lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 3, 'Zwiebel, Paprika, Sellerie und Okra rund 10 Minuten anbraten, in den letzten 2 Minuten Knoblauch und den Rest der Gewürze mitdünsten. Gemüse aus der Pfanne nehmen und zur Seite stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 4, 'Nun kommt der wohl aufwändigste Teil: die Roux. Für die Roux eignet sich eine Pfanne mit schwerem Boden am besten. In der sauberen Pfanne (keine Fleisch- oder Gemüserückstände) Öl erhitzen und langsam mit einem Schneebesen Mehl einrühren. Roux rund 30 Minuten bei mittlerer Hitze unter ständigem Rühren mit einem Holzkochlöffel bräunen. Dabei darauf achten, dass nichts anbrennt (sonst wird es bitter und man muss von vorne beginnen). Das Mehl sollte gegen Ende karamellfarben sein.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 5, 'Fleischbouillon erhitzen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 6, 'Nun das angebratene Gemüse mit der Roux in einem grossen Topf vermengen. Dann langsam mit einem Schöpflöffel heisse Bouillon in den Roux-Gemüsetopf einrühren. Sobald sich die Suppe gut mit dem Rest verbunden hat, den nächsten Schöpflöffel hinzugeben. Auf diese Weise etwa einen halben Liter Suppe beigeben. Den Rest der Suppe langsam unter Rühren zugiessen (mit einem Liter Suppe wird das Gericht eher flüssig, für eine dickflüssigere Konsistenz 1/8 Liter weniger Suppe verwenden).');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 7, 'Wurst und Huhn zugeben und rund 40 Minuten auf kleiner Flamme ohne Deckel köcheln lassen, dabei ab und zu umrühren. Das Gumbo dickt dabei etwas ein. Am Ende abschmecken und gegebenenfalls Nachwürzen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (13, 8, 'Zum Servieren Reis in die Mitte des Tellers geben und Gumbo aufgiessen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (14, 0, 'Lachs auftauen lassen. Rahm erhitzen und Speisestärke einrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (14, 1, 'Gemüsebouillon langsam hinzufügen und aufkochen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (14, 2, 'Tomatenmark, Knoblauchzehe, Pfeffer und Dill hinzugeben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (14, 3, 'Lachs in eine Auflaufform geben und Sauce darübergiessen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (14, 4, 'Alles in den auf 200°C vorgeheizten Ofen geben und ca. 20-30 Minuten backen. Als Beilage empfehle ich Bandnudeln und Brokkoli.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 0, 'Tomaten, Zwiebeln und Zucchini würfeln. Reis nach Packungsanweisung zubereiten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 1, 'Zwiebel mit etwas Öl in eine Pfanne geben und glasig braten. Hackfleisch, Salz, Pfeffer, Cayennepfeffer und Paprikapulver hinzufügen und braten bis das Hackfleisch fast durchgebraten ist.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 2, 'Tomaten hinzufügen und ca. 5 Minuten einkochen lassen. Dann die Zucchini hinzufügen und alles zusammen weitere 5 Minuten braten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 3, 'In der Zwischenzeit in einem weiteren Topf die Sauce zubereiten. Dazu Butter schmelzen und Speistärke einrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 4, 'Mit Gemüsebouillon aufgiessen und den Weisswein hinzufügen. Mit Salz und Pfeffer abschmecken. Backofen auf 200°C vorheizen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 5, 'Reis nun in eine Auflaufform geben, Tomaten-Zucchini-Hackfleisch-Mischung darüben geben und die Sauce darübergiessen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (15, 6, 'Alles mit Käse und (optional) Paniermehl bestreuen und für ca. 15-20 Minuten backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (16, 0, 'Alle Zutaten mischen und in eine Form (Gugelhupf oder Cakeform) geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (16, 1, 'Kuchen bei 180°C ca. 60 Minuten backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (17, 0, 'Für den Teig alle Zutaten von Mehl bis und mit Backpulver mischen und zu einem Teig kneten. Teig in zwei Hälften teilen. Eine Hälfte als Boden in eine Form drücken. Die andere Hälfte zur Seite stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (17, 1, 'Für die Füllung alle restlichen Zutaten mischen und auf den Teig geben. Restliche Hälfte des Teiges als Streusel darüber streuen. Alles bei 180°C ca. 60 Minuten backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (18, 0, 'Sushireis in einem Sieb unter fliessendem kalten Wasser abspülen bis das Wasser klar abläuft (darf nicht mehr milchig sein). Körner kurz abtropfen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (18, 1, 'Reis mit 300 ml Wasser aufkochen und 2 Minuten kochen lassen. Danach die Hitze reduzieren und den Reis zugedeckt bei schwacher Hitze 10 Min quellen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (18, 2, 'Den Deckel abnehmen, 2 Lagen Küchenpapier zwischen Topf und Deckel klemmen und den Reis weitere 15 Minuten quellen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (18, 3, 'In der Zwischenzeit Reisessig, Salz und Zucker kurz aufkochen und wieder etwas abkühlen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (18, 4, 'Reis in eine Schüssel füllen, den Würzessig unterrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (19, 0, 'Reis nach Packungsanweisung zubereiten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (19, 1, 'Alle Zutaten (ausser den Reis) braten und saure Sahne einkochen lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (19, 2, 'Alles in eine Auflaufform schichten, etwas geriebenen Käse und Paniermehl darüber streuen und bei 200°C im Ofen backen bis der Käse geschmolzen ist.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 0, 'Boden: Für den Boden die Butter schmelzen und die Kekse zerkrümmeln. Anschliessend Butter, 2 TL Zucker, zerkrümmelte Kekse, gemahlene Mandeln mit 2 Tropfen Mandelaroma mischen. Die Zutaten in eine vorbereitete Form (Rezept entspricht einer Form von 26cm) drücken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 1, 'Weisse Schokolade schmelzen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 2, 'Philadelphia mit Zucker und Mehl cremig rühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 3, 'Schokolade unterrühren, Eier, Mandelaroma und ausgekratze Vanilleschote hinzufügen und cremig rühren. Masse zum Boden in die Form giessen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 4, 'Nun die Himbeerkonfitüre mit etwas Wasser mischen und anschliessend beliebig auf den Kuchen geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 5, 'Im Ofen ca. 40 Minuten bei 175°C Heissluft backen bis die Oberseite leicht braun wird. Abkühlen lassen und für mehrere Stunden in den Kühlschrank stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (20, 6, 'Am Ende die Aprikosenkonfitüre mit etwas Wasser mischen und den Rand des Kuchens damit bestreichen. Mandelblättchen andrücken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (21, 0, 'Kartoffeln mit einer grossen Reibe in eine Schüssel geben wenn nötig Zellwasser abgiessen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (21, 1, 'Alle weiteren Zutaten in die Schüssel dazugeben und unterrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (21, 2, 'Portionsweise (ein Suppenlöffel) in einer Bratpfanne mit Öl goldbraun herausbacken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (22, 0, '1 grosse Zwiebel klein Würfeln mit 1EL Öl in einem grossen Topf anschwitzen');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (22, 1, 'Kartoffeln würfeln und zusammen mit dem Paprika, Kümmel und Knoblauch zu den angeschwitzen Zwiebeln in den Topf geben und mit Wasser auffüllen bis die Kartoffeln gedeckt sind.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (22, 2, 'Die Karotten in Scheiben schneiden, genauso die Essiggurken und zusammen mit einem Schuss Essig aus dem Gurkenglas in den Topf geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (22, 3, '60 bis 90min auf Niedriger bis Mittlerer Hitze garen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (22, 4, 'Am Ende zum Verfeinern und Abschmecken kann man je nach Geschmack 6 Wienerwürstchen, etwas sauren Rahm und Sambal Olek dazugeben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (23, 0, 'Die Kartoffeln mit Wasser bedeckt etwa 30-40min weich kochen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (23, 1, 'Die Kartoffeln noch lauwarm schälen und in Scheiben schneiden.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (23, 2, 'Alle anderen Zutaten in eine Schüssel geben und zu einer Salatsauce vermischen und direk über die noch warmen Kartoffeln geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (24, 0, 'Bärlauch waschen, Pinienkerne zerhacken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (24, 1, 'Alles Zutaten in den Mixer geben und mixen. Abschmecken und servieren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 0, 'Waldbeeren zusammen mit dem Puderzucker in einen Topf geben und aufkochen. Jenachdem wie stark man die Früchte eingekocht haben möchten köcheln lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 1, 'Rahm steifschlagen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 2, 'Mascarpone in eine Schüssel geben. Rahm unterrühren. Puderzucker, Vanillezucker hinzugeben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 3, 'Vanilleschote auskratzen und das ausgekratzte Mark zur Mascarpone-Rahm-Masse hinzufügen. Alles gut verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 4, 'Schüssel bereitstellen. In jede Schüssel einen Butterkeks zerbröseln.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 5, 'Mascarpone-Rahm-Creme im Wechsel mit den Waldbeeren in die Schüssel schichten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (25, 6, 'Nach Wunsch dekorieren, z.B. mit Schokosplittern, und servieren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 0, 'Boden zubereiten: Butter schmelzen und die Kekse in einem Plastikbeutel mit einem Wallholz fein zermahlen. Die gemahlenen Kekse in eine Schüssel geben und die geschmolzene Butter darunter mischen und gut verrühren. Alles in eine vorbereitete Form geben und den Boden andrücken. Kühl stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 1, 'Nun die Cheesecake-Masse zubereiten: Avocados schälen, würfeln und zusammen mit dem Limettensaft pürieren. Creme Fraiche und Puderzucker daruntermischen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 2, 'Gelatine für 5 Minuten in kaltes Wasser legen. Anschliessend das Wasser gut ausdrücken und mit den 2 EL Wasser auflösen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 3, '2 EL der Masse in die geschmolzene Gelatine geben, gut verrühren und anschliessend zum Rest der Masser geben. Zügig alles miteinander verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 4, 'Rahm steif schlagen und unter die Masse heben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 5, 'Masse auf den Boden geben und für 45 Minuten kühl stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 6, 'Himbeeren: Gelatine für 5 Minuten in kaltes Wasser legen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 7, 'Währenddessen die Himbeeren mit dem Puderzucker aufkochen. Gelatine gut ausdrücken und mit in den Topf geben.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (26, 8, 'Himbeermasse auf dem Kuchen verteilen und für ca. 3 Stunden kühl stellen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (27, 0, 'Zwiebeln und Kartoffeln schälen und würfeln. Karotten in Scheiben, Chinakohl in Streifen schneiden. Alles zusammen fettfrei anrösten. Gemüsebouillon dazugiessen und für 5 Minuten köcheln.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (27, 1, 'Tomaten vierteln und Okras in Scheiben schneiden. Beides in die Suppe geben und weiter köcheln.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (27, 2, 'Erdnusscreme und Gewürze hinzufügen, weitere 5 Minuten köcheln.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (28, 0, 'Butter schmelzen und zusammen mit allen anderen Zutaten zu einem dicken Teig rühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (28, 1, 'Den Teig portionsweise (etwa 1 Schöpflöffel) in einer angefetteten Pfanne bei mittlerer Temperatur goldbraun backen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (28, 2, 'Den Pancake drehen wenn der Teig auf der Oberseite stabile Blasen wirft.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 0, 'Margerine in eine Schüssel geben und geschmeidig rühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 1, 'Zutaten bis Mehl dazugeben und mischen');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 2, 'Mehl und Backpulver dazusieben und zu einem Teig kneten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 3, 'Aus dem Teig Rollen formen mit 4-5cm durchmesser und in einem Kühlschrank oder Tiefkühler fest werden lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 4, 'Den Teig in 3-4mm Dicke scheiben schneiden und auf ein Blech legen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (29, 5, '6-8min bei 220 Grad im vorgeheizten Ofen hellbraun werden lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (31, 0, 'Bier und Mehl mit dem Schwingbesen verrühren mit etwas Salz abschmecken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (31, 1, 'Pro Person 160g Eglifilet würzen (Fleischgewürz) und leicht mehlen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (31, 2, 'Durch den Teig ziehen und am Schüsselrand abstreifen, nur wenig Teig nehmen und schwimmend im Erdnussöl bei 180°C 2min herausbacken.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (31, 3, 'Auf Küchenpapier abtropfen lassen und dann mit einer halben Zitrone und Sauce Tatar servieren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (32, 0, 'Reis nach Packungsanweisung zubereiten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (32, 1, 'Panade vorbereiten: Dazu das Mehl und 1 TL Backpulver sowie den scharfen Paprika, Salz und Pfeffer vermischen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (32, 2, 'Marinade vorbereiten Dazu das Ei, das Knoblauchpulver, Salz, edelsüssen Paprika und Cayennepfeffer miteinander verrühren.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (32, 3, 'Fleisch zuerst in die Marinade tauchen und anschliessend durch die Panaden-Mischung ziehen. Alles in eine Pfanne geben und braten.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (32, 4, 'Sauce zubereiten Rahm mit Mehl gut verrühren. Kurkuma, Currypulver, Salz und Pfeffer hinzufügen. Den Fruchtcocktail hineingeben und alles zusammen aufkochen, ca. 5 Minuten auf kleiner Stufe köcheln lassen.');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (33, 0, 'Teigwaren und alle Zutaten bis und mit Bouillon in eine grossen Topf geben, mischen, aufkochen. Offen unter gelegentlichem Rühren bei mittlerer Hitze ca. 20 Min kochen');
INSERT INTO recipe_steps (recipe_id, sort_order, text) VALUES (33, 1, 'Käse daruntermischen, abschmecken, Röstzwiebeln darauf verteilen.');
