INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (1, 1, 'Kann wunderbar mit der Hamburger Special Sauce verfeinert werden.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (11, 1, 'Dazu passen verschiedene Fruchtkompotts, bei uns am beliebtesten sind eingelegte Birnen oder Zwetschgenröster. Aber auch Apfelmus passt gut dazu.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (20, 1, 'Mandelblättchen für den Rand vorher leicht anrösten bis sie braun sind.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (21, 1, 'Ein Teil der Kartoffeln mit geriebenen Zucchini / Zucchetti ersetzen.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (22, 1, 'Beim zweiten mal Aufkochen ist das Gericht noch besser.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (23, 1, 'Mit einigen Oliven oder Essiggurken die Sauce aufpeppen');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (25, 1, 'Lässt sich auch gut mit anderen Früchten, z.B. Erdbeeren, zubereiten.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (25, 2, 'Rahm mit Sahnesteif schlagen.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (26, 1, 'Himbeermasse nach dem Kochen durch ein Sieb giessen und dann auf den Kuchen geben. Dies ergibt eine glatte Oberfläche.');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (28, 1, 'Das Eiweiss muss nicht separat geschlagen werden, aber wenn man es macht werden die Pancakes noch luftiger');
INSERT INTO recipe_hints (recipe_id, sort_order, text) VALUES (31, 1, 'Das würzen des Fisches macht diese Chnuschperli zu einem einmaligen Genuss.');
